library(shiny)
library(dplyr)
library(tidyr)
library(gt)
library(stringr)

load(url("https://raw.githubusercontent.com/lukysmarek/exposure/main/data/models_exposure.Rdata"))
# load("data/models_exposure.Rdata")

server <- function(input, output, session) {
  observe({
    # Enforce at least one selection
    if (is.null(input$model_exposure) || length(input$model_exposure) == 0) {
      updateSelectInput(session, "model_exposure", selected = "Supermarket")
    }
  })
  
  observe({
    # Enforce at least one selection
    if (is.null(input$model_type) || length(input$model_type) == 0) {
      updateCheckboxGroupInput(session, "model_type", selected = "adjusted")
    }
  })
  
  observe({
    # Enforce at least one selection
    if (is.null(input$condition) || length(input$condition) == 0) {
      updateSelectInput(session, "condition", selected = "All")
    }
  })

  observe({
    # Enforce at least one selection
    if (is.null(input$model_type2) || length(input$model_type2) == 0) {
      updateCheckboxGroupInput(session, "model_type2", selected = "adjusted")
    }
  })
  
  observe({
    # Enforce at least one selection
    if (is.null(input$condition2) || length(input$condition2) == 0) {
      updateSelectInput(session, "condition2", selected = "All")
    }
  })
  
  
  filtered_data <- reactive({
    df <- models
    
    # filtering exposures
    df <- df %>% filter(Exposure %in% input$model_exposure)
    
    # filtering covariates
    if (!isTRUE(input$show_covars)) {
      df <- df %>% filter(var_description != "Covariate" | var_description == "Exposure")
    } else {
      df <- df
    }
    # filtering summary
    if (!isTRUE(input$show_summary)) {
      df <- df %>% filter(var_description != "summary"  | var_description == "Exposure")
    } else {
      df <- df
    }
    
    # filtering adjusted/unadjusted
    df <- df %>% filter(model %in% input$model_type)
    
    # filtering conditions
    df <- df %>% 
      filter(condition %in% input$condition) %>% 
      select(-var_description)
    
    # pivoting
    df <- df %>% 
      pivot_wider(values_from = c(`OR (95%CI)`, `p-value`), names_from = c(condition, model), names_vary = "slowest", names_glue = "{condition}_{model}_{.value}")
    
    # creating and tweaking gt
    df <- df %>%
      rename(` `=term) %>%
      group_by(Exposure) %>%
      gt() %>%
      gt::tab_spanner_delim(delim = "_") %>%
      sub_missing(columns = everything(), missing_text = "") %>% 
      tab_style(
        style = cell_text(weight = "bold"),
        locations = cells_column_spanners()
      ) %>% 
      tab_style(
        locations = cells_row_groups(),
        style = cell_text(weight = "bolder", style = "oblique")
      ) %>% 
      {
        if (!isTRUE(input$show_pval)){
          cols_hide(., contains("p-value"))
        } else {
          fmt_number(., contains('p-value'), decimals = 3) %>%
            fmt(., columns = contains('p-value'),
                fns = function(x) ifelse(x < 0.001, "<0.001", sprintf("%.3f", x))
            ) 
        }
        }
  })
  
  filtered_data2 <- reactive({
    qg <- qgmodels
    
    # filtering covariates
    if (!isTRUE(input$show_covars2)) {
      qg <- qg %>% filter(var_description != "Covariate" | var_description == "Exposure")
    } else {
      qg <- qg
    }
    # filtering summary
    if (!isTRUE(input$show_summary2)) {
      qg <- qg %>% filter(var_description != "summary"  | var_description == "Exposure")
    } else {
      qg <- qg
    }
    
    # filtering adjusted/unadjusted
    qg <- qg %>% filter(model %in% input$model_type2)
    
    # filtering conditions
    qg <- qg %>% 
      filter(condition %in% input$condition2) %>% 
      select(-var_description)
    
    # pivoting
    qg <- qg %>% 
      pivot_wider(values_from = c(`OR (95%CI) | weight`, `p-value`), names_from = c(condition, model), names_vary = "slowest", names_glue = "{condition}_{model}_{.value}")
    
    # creating and tweaking gt
    qg <- qg %>%
      rename(` `=term) %>%
      gt() %>%
      gt::tab_spanner_delim(delim = "_") %>%
      sub_missing(columns = everything(), missing_text = "") %>% 
      tab_style(
        style = cell_text(weight = "bold"),
        locations = cells_column_spanners()
      ) %>% 
      {
        if (!isTRUE(input$show_pval2)){
          cols_hide(., contains("p-value")) %>% 
            tab_style(.,
              locations = cells_row_groups(),
              style = cell_text(weight = "bolder", style = "oblique")
            )
        } else {
          tab_style(.,
            locations = cells_row_groups(),
            style = cell_text(weight = "bolder", style = "oblique")
          )
        }
        }
  })
  
  m <- reactive({inp <- input$show_pval})
  
  # output$nrows <- renderText((m()))
  # output$tbl <- gt::render_gt({filtered_data() %>% gt()})
  output$tbl <- gt::render_gt({filtered_data()})
  output$tbl2 <- gt::render_gt({filtered_data2()})
  output$downloadData <- downloadHandler(
    filename = function() {"models_export.xlsx"},
    # content = function(file){file.copy("data/models_export.xlsx", file)}
    content = function(file){file.copy(url("https://raw.githubusercontent.com/lukysmarek/exposure/main/data/models_export.xlsx"), file)}
  )
  
}
